+import AppKit
+import SwiftUI
+
+struct NewWorkspaceSheet: View {
+    let tabManager: TabManager
+    @Environment(\.theme) private var theme
+    @State private var name = "Workspace"
+    @State private var locationPath: String
+    @FocusState private var nameFieldFocused: Bool
+
+    init(tabManager: TabManager) {
+        self.tabManager = tabManager
+        _locationPath = State(initialValue: Self.defaultLocationPath(for: tabManager))
+    }
+
+    var body: some View {
+        VStack(spacing: Spacing.lg) {
+            header
+            form
+            actions
+        }
+        .padding(Spacing.xl)
+        .frame(width: 460)
+        .background(theme.backgroundSwiftUI)
+        .tint(theme.accentSwiftUI)
+        .onAppear {
+            nameFieldFocused = true
+        }
+    }
+
+    private var header: some View {
+        Text("New Workspace")
+            .font(Typography.headline)
+            .foregroundStyle(theme.textPrimarySwiftUI)
+            .frame(maxWidth: .infinity, alignment: .leading)
+    }
+
+    private var form: some View {
+        VStack(alignment: .leading, spacing: Spacing.md) {
+            VStack(alignment: .leading, spacing: Spacing.sm) {
+                Text("Name")
+                    .font(Typography.subheadline)
+                    .foregroundStyle(theme.textSecondarySwiftUI)
+                TextField("Workspace", text: $name)
+                    .textFieldStyle(.roundedBorder)
+                    .font(Typography.body)
+                    .focused($nameFieldFocused)
+                    .onSubmit(createIfValid)
+            }
+
+            VStack(alignment: .leading, spacing: Spacing.sm) {
+                Text("Location")
+                    .font(Typography.subheadline)
+                    .foregroundStyle(theme.textSecondarySwiftUI)
+                HStack(spacing: Spacing.sm) {
+                    TextField("Folder path", text: $locationPath)
+                        .textFieldStyle(.roundedBorder)
+                        .font(Typography.body)
+                        .onSubmit(createIfValid)
+                    Button {
+                        chooseLocation()
+                    } label: {
+                        LucideLabel("Choose...", lucide: .folder)
+                    }
+                    .vesperGhostButtonStyle()
+                }
+
+                if !isLocationValid {
+                    Text("Choose an existing folder.")
+                        .font(Typography.footnote)
+                        .foregroundStyle(theme.errorSwiftUI)
+                }
+            }
+        }
+    }
+
+    private var actions: some View {
+        HStack(spacing: Spacing.sm) {
+            Spacer()
+            Button("Cancel") {
+                tabManager.showNewWorkspaceSheet = false
+            }
+            .keyboardShortcut(.escape, modifiers: [])
+
+            Button("Create") {
+                createIfValid()
+            }
+            .keyboardShortcut(.return, modifiers: .command)
+            .disabled(!canCreate)
+        }
+    }
+
+    private var canCreate: Bool {
+        !trimmedName.isEmpty && isLocationValid
+    }
+
+    private var trimmedName: String {
+        name.trimmingCharacters(in: .whitespacesAndNewlines)
+    }
+
+    private var expandedLocationPath: String {
+        (locationPath.trimmingCharacters(in: .whitespacesAndNewlines) as NSString).expandingTildeInPath
+    }
+
+    private var isLocationValid: Bool {
+        var isDirectory: ObjCBool = false
+        let exists = FileManager.default.fileExists(atPath: expandedLocationPath, isDirectory: &isDirectory)
+        return exists && isDirectory.boolValue
+    }
+
+    private func createIfValid() {
+        guard canCreate else { return }
+        tabManager.newWorkspace(
+            name: trimmedName,
+            workingDirectory: expandedLocationPath,
+            startRenaming: false
+        )
+        tabManager.showNewWorkspaceSheet = false
+    }
+
+    private func chooseLocation() {
+        let panel = NSOpenPanel()
+        panel.title = "Choose Workspace Folder"
+        panel.message = "Choose the folder where this workspace should start."
+        panel.prompt = "Choose"
+        panel.canChooseFiles = false
+        panel.canChooseDirectories = true
+        panel.allowsMultipleSelection = false
+        panel.canCreateDirectories = true
+        panel.resolvesAliases = true
+        panel.directoryURL = URL(fileURLWithPath: Self.validDirectoryPath(expandedLocationPath), isDirectory: true)
+
+        panel.begin { response in
+            guard response == .OK, let url = panel.url else { return }
+            locationPath = url.path
+        }
+    }
+
+    private static func defaultLocationPath(for tabManager: TabManager) -> String {
+        let selectedPath = tabManager.selectedWorkspace?.currentDirectory ?? NSHomeDirectory()
+        return validDirectoryPath((selectedPath as NSString).expandingTildeInPath)
+    }
+
+    private static func validDirectoryPath(_ path: String) -> String {
+        var isDirectory: ObjCBool = false
+        if FileManager.default.fileExists(atPath: path, isDirectory: &isDirectory),
+           isDirectory.boolValue {
+            return path
+        }
+        return NSHomeDirectory()
+    }
+}
