+import Foundation
+import Testing
+
+@testable import Vesper
+
+@Suite("New workspace popup", .serialized)
+@MainActor
+struct NewWorkspacePopupTests {
+    @Test("requestNewWorkspace opens popup without creating a workspace")
+    func requestNewWorkspaceOnlyShowsSheet() {
+        let workspace = Workspace(name: "Existing")
+        let manager = TabManager(workspaces: [workspace])
+        defer { manager.shutdown() }
+
+        manager.requestNewWorkspace()
+
+        #expect(manager.showNewWorkspaceSheet)
+        #expect(manager.workspaces.count == 1)
+        #expect(manager.workspaces.first?.id == workspace.id)
+    }
+
+    @Test("popup confirmation creates named workspace at chosen location")
+    func newWorkspaceCanSetNameAndLocationWithoutInlineRename() throws {
+        let manager = TabManager(workspaces: [Workspace(name: "Existing")])
+        defer { manager.shutdown() }
+        let directory = FileManager.default.temporaryDirectory.path
+
+        manager.newWorkspace(
+            name: " Project ",
+            workingDirectory: directory,
+            startRenaming: false
+        )
+
+        let workspace = try #require(manager.selectedWorkspace)
+        let tab = try #require(workspace.selectedTab)
+        #expect(workspace.name == "Project")
+        #expect(tab.workingDirectory == directory)
+        #expect(manager.pendingRenameWorkspaceID == nil)
+    }
+
+    @Test("legacy direct creation still starts inline rename")
+    func directNewWorkspaceKeepsInlineRename() throws {
+        let manager = TabManager(workspaces: [Workspace(name: "Existing")])
+        defer { manager.shutdown() }
+
+        manager.newWorkspace()
+
+        let workspace = try #require(manager.selectedWorkspace)
+        #expect(workspace.name == "Workspace")
+        #expect(manager.pendingRenameWorkspaceID == workspace.id)
+    }
+
+    @Test("new workspace actions open the popup")
+    func entryPointsRequestPopup() throws {
+        let commandSource = try Self.source("Helpers/KeyboardShortcuts.swift")
+        let sidebarSource = try Self.source("Views/Sidebar/SidebarView.swift")
+        let paletteSource = try Self.source("Views/Components/CommandPalette.swift")
+        let contentSource = try Self.source("Views/ContentView.swift")
+        let sheetSource = try Self.source("Views/Components/NewWorkspaceSheet.swift")
+
+        #expect(commandSource.contains("tabManager.requestNewWorkspace()"))
+        #expect(sidebarSource.contains("tabManager.requestNewWorkspace()"))
+        #expect(paletteSource.contains("tabManager?.requestNewWorkspace()"))
+        #expect(contentSource.contains(".sheet(isPresented: $tabManager.showNewWorkspaceSheet)"))
+        #expect(sheetSource.contains("TextField(\"Workspace\", text: $name)"))
+        #expect(sheetSource.contains("TextField(\"Folder path\", text: $locationPath)"))
+        #expect(sheetSource.contains("NSOpenPanel()"))
+    }
+
+    private static func source(_ relativePath: String) throws -> String {
+        let url = URL(fileURLWithPath: #filePath)
+            .deletingLastPathComponent()
+            .deletingLastPathComponent()
+            .appendingPathComponent("Sources")
+            .appendingPathComponent(relativePath)
+        return try String(contentsOf: url, encoding: .utf8)
+    }
+}
